def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
        else:
            ratio = item / capacity
            if ratio > 2:
                priorities[i] = ratio ** 4 - 2 * np.sqrt(ratio)
            elif 1 < ratio <= 2:
                temp = 0
                for k in range(5, 0, -1):
                    if k % 2 == 0:
                        temp += (ratio ** k) / (k + 1)
                    else:
                        temp -= (ratio ** k) / (k + 1)
                priorities[i] = temp + np.exp(-ratio)
            elif ratio == 1:
                priorities[i] = 1 + np.sin(capacity % np.pi)
            elif ratio < 1:
                val = 0
                for power in range(1, 6):
                    val += ((-1) ** power) * (ratio ** power) / power
                if val == 0:
                    priorities[i] = 0
                else:
                    adjusted_val = -np.log(abs(val)) + np.tanh(ratio * capacity)
                    if adjusted_val < 0:
                        priorities[i] = abs(adjusted_val) * 0.5
                    else:
                        priorities[i] = adjusted_val
            else:
                priorities[i] = ratio
    return priorities
